import { randomUUID, scryptSync, timingSafeEqual } from "crypto";
import { prisma } from "@/lib/prisma";

type AccountRow = {
  id: string;
  name: string;
  username: string;
  password_hash: string;
  default_delivery_line1?: string | null;
  default_delivery_line2?: string | null;
  default_landmark?: string | null;
  default_area?: string | null;
};

function normalizeUsername(input: string) {
  return String(input || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9_]/g, "");
}

function isUsernameValid(username: string) {
  return /^[a-z0-9_]{4,24}$/.test(username);
}

function hashPassword(password: string) {
  const salt = randomUUID().replace(/-/g, "");
  const hash = scryptSync(password, salt, 64).toString("hex");
  return `${salt}:${hash}`;
}

function verifyPassword(password: string, stored: string) {
  const [salt, hash] = String(stored || "").split(":");
  if (!salt || !hash) return false;
  const incoming = scryptSync(password, salt, 64);
  const known = Buffer.from(hash, "hex");
  if (incoming.length !== known.length) return false;
  return timingSafeEqual(incoming, known);
}

async function ensureTable() {
  await prisma.$executeRawUnsafe(`
    CREATE TABLE IF NOT EXISTS customer_accounts (
      id TEXT PRIMARY KEY,
      name TEXT NOT NULL,
      username TEXT NOT NULL UNIQUE,
      password_hash TEXT NOT NULL,
      created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
    )
  `);
  const cols = (await prisma.$queryRawUnsafe(`PRAGMA table_info(customer_accounts)`)) as Array<{
    name: string;
  }>;
  const hasPhone = cols.some((c) => String(c.name) === "phone");
  const hasUsername = cols.some((c) => String(c.name) === "username");

  // Legacy table used phone; migrate to username-based schema once.
  if (hasPhone || !hasUsername) {
    await prisma.$executeRawUnsafe(`
      CREATE TABLE IF NOT EXISTS customer_accounts_v2 (
        id TEXT PRIMARY KEY,
        name TEXT NOT NULL,
        username TEXT NOT NULL UNIQUE,
        password_hash TEXT NOT NULL,
        created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
      )
    `);
    const usernameExpr = hasUsername
      ? `COALESCE(NULLIF(username, ''), lower(replace(replace(replace(phone, '+', ''), ' ', ''), '-', '')))`
      : `lower(replace(replace(replace(phone, '+', ''), ' ', ''), '-', ''))`;
    await prisma.$executeRawUnsafe(`
      INSERT OR IGNORE INTO customer_accounts_v2 (id, name, username, password_hash, created_at)
      SELECT id, name, ${usernameExpr}, password_hash, COALESCE(created_at, CURRENT_TIMESTAMP)
      FROM customer_accounts
    `);
    await prisma.$executeRawUnsafe(`DROP TABLE customer_accounts`);
    await prisma.$executeRawUnsafe(`ALTER TABLE customer_accounts_v2 RENAME TO customer_accounts`);
  }
  const freshCols = (await prisma.$queryRawUnsafe(`PRAGMA table_info(customer_accounts)`)) as Array<{
    name: string;
  }>;
  const colSet = new Set(freshCols.map((c) => String(c.name)));
  if (!colSet.has("default_delivery_line1")) {
    await prisma.$executeRawUnsafe(`ALTER TABLE customer_accounts ADD COLUMN default_delivery_line1 TEXT`);
  }
  if (!colSet.has("default_delivery_line2")) {
    await prisma.$executeRawUnsafe(`ALTER TABLE customer_accounts ADD COLUMN default_delivery_line2 TEXT`);
  }
  if (!colSet.has("default_landmark")) {
    await prisma.$executeRawUnsafe(`ALTER TABLE customer_accounts ADD COLUMN default_landmark TEXT`);
  }
  if (!colSet.has("default_area")) {
    await prisma.$executeRawUnsafe(`ALTER TABLE customer_accounts ADD COLUMN default_area TEXT`);
  }
  await prisma.$executeRawUnsafe(`CREATE UNIQUE INDEX IF NOT EXISTS idx_customer_accounts_username ON customer_accounts (username)`);
}

export function buildUsernameSuggestions(firstName: string, lastName: string) {
  const f = normalizeUsername(firstName) || "user";
  const l = normalizeUsername(lastName);
  const l4 = l ? l.slice(0, 4) : "user";
  const l3 = l ? l.slice(0, 3) : "app";
  const base = `${f}${l4}`.slice(0, 16) || "user";
  return [
    `${base}`,
    `${f}21${l4}`,
    `${base}1`,
    `${base}21`,
    `${f}_${l3}`,
    `${f}${l ? l.slice(0, 2) : ""}${Math.floor(10 + Math.random() * 89)}`,
    `${f}_${l3}${Math.floor(100 + Math.random() * 900)}`,
  ].map((x) => normalizeUsername(x).slice(0, 24));
}

export async function getAvailableUsernames(candidates: string[]) {
  await ensureTable();
  const out: string[] = [];
  for (const c of candidates) {
    const username = normalizeUsername(c);
    if (!isUsernameValid(username)) continue;
    const rows = (await prisma.$queryRawUnsafe(
      `SELECT id FROM customer_accounts WHERE username = ? LIMIT 1`,
      username
    )) as Array<{ id: string }>;
    if (rows.length === 0) out.push(username);
  }
  return Array.from(new Set(out));
}

export async function suggestAvailableUsernames(firstName: string, lastName: string, limit = 5) {
  const baseCandidates = buildUsernameSuggestions(firstName, lastName);
  const available = await getAvailableUsernames(baseCandidates);
  if (available.length >= limit) return available.slice(0, limit);

  const f = normalizeUsername(firstName) || "user";
  const l = normalizeUsername(lastName);
  const l4 = l ? l.slice(0, 4) : "user";
  const extraCandidates: string[] = [];
  for (let i = 11; i <= 99 && available.length + extraCandidates.length < limit + 10; i++) {
    extraCandidates.push(`${f}${i}${l4}`);
    extraCandidates.push(`${f}_${l4}${i}`);
  }

  const extraAvailable = await getAvailableUsernames(extraCandidates);
  return Array.from(new Set([...available, ...extraAvailable])).slice(0, limit);
}

export async function registerLocalAccount(name: string, usernameInput: string, password: string) {
  const username = normalizeUsername(usernameInput);
  if (!name.trim()) throw new Error("Name is required.");
  if (!isUsernameValid(username)) throw new Error("Username must be 4-24 chars (a-z, 0-9, _).");
  if (String(password || "").length < 6) throw new Error("Password must be at least 6 characters.");

  await ensureTable();

  const existing = (await prisma.$queryRawUnsafe(
    `SELECT id FROM customer_accounts WHERE username = ? LIMIT 1`,
    username
  )) as Array<{ id: string }>;

  if (existing.length > 0) throw new Error("Username already taken.");

  const id = randomUUID().replace(/-/g, "");
  const passwordHash = hashPassword(password);

  await prisma.$executeRawUnsafe(
    `INSERT INTO customer_accounts (id, name, username, password_hash) VALUES (?, ?, ?, ?)`,
    id,
    name.trim(),
    username,
    passwordHash
  );

  return { id, name: name.trim(), username };
}

export async function loginLocalAccount(usernameInput: string, password: string) {
  const username = normalizeUsername(usernameInput);
  if (!isUsernameValid(username)) throw new Error("Valid username is required.");
  if (!password) throw new Error("Password is required.");

  await ensureTable();

  const rows = (await prisma.$queryRawUnsafe(
    `SELECT id, name, username, password_hash FROM customer_accounts WHERE username = ? LIMIT 1`,
    username
  )) as AccountRow[];

  const acc = rows[0];
  if (!acc) throw new Error("Account not found.");

  const ok = verifyPassword(password, acc.password_hash);
  if (!ok) throw new Error("Invalid password.");

  return { id: acc.id, name: acc.name, username: acc.username };
}

export async function getLocalAccountProfile(usernameInput: string) {
  const username = normalizeUsername(usernameInput);
  if (!isUsernameValid(username)) return null;
  await ensureTable();

  const rows = (await prisma.$queryRawUnsafe(
    `SELECT id, name, username, default_delivery_line1, default_delivery_line2, default_landmark, default_area
     FROM customer_accounts WHERE username = ? LIMIT 1`,
    username
  )) as AccountRow[];

  const acc = rows[0];
  if (!acc) return null;
  return {
    id: acc.id,
    name: acc.name,
    username: acc.username,
    defaultAddress: {
      line1: String(acc.default_delivery_line1 || "").trim(),
      line2: String(acc.default_delivery_line2 || "").trim(),
      landmark: String(acc.default_landmark || "").trim(),
      area: String(acc.default_area || "").trim(),
    },
  };
}

export async function saveLocalAccountDefaultAddress(
  usernameInput: string,
  address: { line1?: string | null; line2?: string | null; landmark?: string | null; area?: string | null }
) {
  const username = normalizeUsername(usernameInput);
  if (!isUsernameValid(username)) return;
  await ensureTable();

  const line1 = String(address?.line1 || "").trim();
  if (!line1) return;

  await prisma.$executeRawUnsafe(
    `UPDATE customer_accounts
     SET default_delivery_line1 = ?,
         default_delivery_line2 = ?,
         default_landmark = ?,
         default_area = ?
     WHERE username = ?`,
    line1,
    String(address?.line2 || "").trim() || null,
    String(address?.landmark || "").trim() || null,
    String(address?.area || "").trim() || null,
    username
  );
}
