import { randomUUID } from "crypto";
import { prisma } from "@/lib/prisma";

type WalletTxnRow = {
  id: string;
  username: string;
  type: string;
  amount_paise: number;
  balance_after_paise: number;
  note: string | null;
  ref_order_id: string | null;
  created_at: string;
};

function normalizeUsername(input: string) {
  return String(input || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9_]/g, "");
}

async function ensureWalletTables() {
  await prisma.$executeRawUnsafe(`
    CREATE TABLE IF NOT EXISTS wallet_accounts (
      username TEXT PRIMARY KEY,
      balance_paise INTEGER NOT NULL DEFAULT 0,
      updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
    )
  `);

  await prisma.$executeRawUnsafe(`
    CREATE TABLE IF NOT EXISTS wallet_transactions (
      id TEXT PRIMARY KEY,
      username TEXT NOT NULL,
      type TEXT NOT NULL,
      amount_paise INTEGER NOT NULL,
      balance_after_paise INTEGER NOT NULL,
      note TEXT,
      ref_order_id TEXT,
      created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
    )
  `);

  await prisma.$executeRawUnsafe(
    `CREATE INDEX IF NOT EXISTS idx_wallet_txn_username_created ON wallet_transactions (username, created_at DESC)`
  );
}

export async function getWalletSummary(usernameInput: string) {
  const username = normalizeUsername(usernameInput);
  if (!username) return null;
  await ensureWalletTables();

  await prisma.$executeRawUnsafe(
    `INSERT OR IGNORE INTO wallet_accounts (username, balance_paise) VALUES (?, 0)`,
    username
  );

  const rows = (await prisma.$queryRawUnsafe(
    `SELECT username, balance_paise FROM wallet_accounts WHERE username = ? LIMIT 1`,
    username
  )) as Array<{ username: string; balance_paise: number }>;

  const txns = (await prisma.$queryRawUnsafe(
    `SELECT id, username, type, amount_paise, balance_after_paise, note, ref_order_id, created_at
     FROM wallet_transactions
     WHERE username = ?
     ORDER BY created_at DESC
     LIMIT 50`,
    username
  )) as WalletTxnRow[];

  return {
    username,
    balancePaise: Number(rows[0]?.balance_paise || 0),
    transactions: txns.map((t) => ({
      id: t.id,
      type: t.type,
      amountPaise: Number(t.amount_paise || 0),
      balanceAfterPaise: Number(t.balance_after_paise || 0),
      note: t.note || "",
      refOrderId: t.ref_order_id || "",
      createdAt: t.created_at,
    })),
  };
}

export async function topUpWallet(usernameInput: string, amountPaise: number, note?: string) {
  const username = normalizeUsername(usernameInput);
  if (!username) throw new Error("Invalid username.");
  if (!Number.isFinite(amountPaise) || amountPaise <= 0) throw new Error("Invalid top-up amount.");
  await ensureWalletTables();

  const result = await prisma.$transaction(async (tx) => {
    await tx.$executeRawUnsafe(
      `INSERT OR IGNORE INTO wallet_accounts (username, balance_paise) VALUES (?, 0)`,
      username
    );

    const rows = (await tx.$queryRawUnsafe(
      `SELECT balance_paise FROM wallet_accounts WHERE username = ? LIMIT 1`,
      username
    )) as Array<{ balance_paise: number }>;
    const current = Number(rows[0]?.balance_paise || 0);
    const next = current + Math.round(amountPaise);

    await tx.$executeRawUnsafe(
      `UPDATE wallet_accounts SET balance_paise = ?, updated_at = CURRENT_TIMESTAMP WHERE username = ?`,
      next,
      username
    );

    const txnId = randomUUID().replace(/-/g, "");
    await tx.$executeRawUnsafe(
      `INSERT INTO wallet_transactions (id, username, type, amount_paise, balance_after_paise, note)
       VALUES (?, ?, 'TOPUP', ?, ?, ?)`,
      txnId,
      username,
      Math.round(amountPaise),
      next,
      note || null
    );

    return { balancePaise: next, transactionId: txnId };
  });

  return result;
}

export async function chargeWalletForOrder(args: {
  username: string;
  orderId: string;
  amountPaise: number;
  note?: string;
}) {
  const username = normalizeUsername(args.username);
  const orderId = String(args.orderId || "").trim();
  const amountPaise = Math.round(Number(args.amountPaise || 0));
  if (!username) throw new Error("Invalid username.");
  if (!orderId) throw new Error("Invalid order id.");
  if (!Number.isFinite(amountPaise) || amountPaise <= 0) throw new Error("Invalid wallet charge amount.");
  await ensureWalletTables();

  const result = await prisma.$transaction(async (tx) => {
    await tx.$executeRawUnsafe(
      `INSERT OR IGNORE INTO wallet_accounts (username, balance_paise) VALUES (?, 0)`,
      username
    );

    const dup = (await tx.$queryRawUnsafe(
      `SELECT id FROM wallet_transactions
       WHERE username = ? AND type = 'ORDER_DEBIT' AND ref_order_id = ?
       LIMIT 1`,
      username,
      orderId
    )) as Array<{ id: string }>;
    if (dup.length > 0) {
      const rows = (await tx.$queryRawUnsafe(
        `SELECT balance_paise FROM wallet_accounts WHERE username = ? LIMIT 1`,
        username
      )) as Array<{ balance_paise: number }>;
      return { balancePaise: Number(rows[0]?.balance_paise || 0), charged: false };
    }

    const rows = (await tx.$queryRawUnsafe(
      `SELECT balance_paise FROM wallet_accounts WHERE username = ? LIMIT 1`,
      username
    )) as Array<{ balance_paise: number }>;
    const current = Number(rows[0]?.balance_paise || 0);
    if (current < amountPaise) throw new Error("Insufficient wallet balance.");
    const next = current - amountPaise;

    await tx.$executeRawUnsafe(
      `UPDATE wallet_accounts SET balance_paise = ?, updated_at = CURRENT_TIMESTAMP WHERE username = ?`,
      next,
      username
    );

    const txnId = randomUUID().replace(/-/g, "");
    await tx.$executeRawUnsafe(
      `INSERT INTO wallet_transactions (id, username, type, amount_paise, balance_after_paise, note, ref_order_id)
       VALUES (?, ?, 'ORDER_DEBIT', ?, ?, ?, ?)`,
      txnId,
      username,
      amountPaise,
      next,
      args.note || null,
      orderId
    );

    return { balancePaise: next, charged: true };
  });

  return result;
}

