import { NextRequest, NextResponse } from "next/server";
import { getSessionFromRequest } from "@/lib/auth-server";
import { getLocalAccountProfile } from "@/lib/local-auth-db";
import { getWalletSummary, topUpWallet } from "@/lib/wallet-db";

export async function GET(req: NextRequest) {
  const session = getSessionFromRequest(req);
  if (!session) return NextResponse.json({ authenticated: false }, { status: 200 });
  const profile = await getLocalAccountProfile(session.username);
  const wallet = await getWalletSummary(session.username);
  const defaultAddress = profile?.defaultAddress ?? {
    line1: "",
    line2: "",
    landmark: "",
    area: "",
  };

  return NextResponse.json(
    {
      authenticated: true,
      user: {
        name: profile?.name || session.name,
        username: session.username,
        defaultAddress,
        walletBalancePaise: wallet?.balancePaise ?? 0,
        walletTransactions: wallet?.transactions ?? [],
      },
    },
    { status: 200 }
  );
}

export async function POST(req: NextRequest) {
  try {
    const session = getSessionFromRequest(req);
    if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

    const body = await req.json().catch(() => ({}));
    const action = String(body?.action || "").trim().toLowerCase();

    if (action === "topup") {
      const amountRupees = Number(body?.amountRupees || 0);
      const amountPaise = Math.round(amountRupees * 100);
      if (!Number.isFinite(amountRupees) || amountRupees <= 0) {
        return NextResponse.json({ error: "Invalid amount." }, { status: 400 });
      }
      const maxTopupRupees = 10000;
      if (amountRupees > maxTopupRupees) {
        return NextResponse.json({ error: `Top-up limit is Rs ${maxTopupRupees}.` }, { status: 400 });
      }

      const topped = await topUpWallet(session.username, amountPaise, "Manual top-up");
      return NextResponse.json({ ok: true, walletBalancePaise: topped.balancePaise }, { status: 200 });
    }

    return NextResponse.json({ error: "Invalid action." }, { status: 400 });
  } catch (e: any) {
    return NextResponse.json({ error: e?.message || "Server error" }, { status: 500 });
  }
}
